@dataclass
class VideoGenerationConfig:
    provider: VideoProvider = VideoProvider.REPLICATE
    default_duration: int = 5
    default_aspect_ratio: str = "16:9"
    max_retries: int = 3
    timeout: int = 600
    output_dir: str = "./generated_videos"

class VideoGenerationService:
    async def generate(self, prompt: str,
                       provider: Optional[VideoProvider] = None, **kwargs) -> dict:
        provider = provider or self.config.provider
        for attempt in range(self.config.max_retries):
            try:
                result = await self._dispatch(provider, prompt, **kwargs)
                if result["status"] == "success":
                    output_path = await self._download_video(result["video_url"], prompt[:50])
                    result["local_path"] = output_path
                return result
            except Exception as e:
                if attempt == self.config.max_retries - 1:
                    return {"status": "failed", "error": str(e)}
